const crypto = require('crypto');
const item = $input.first();
const sourceHeaders = item.json.headers ?? {};
const headers = {};
for (const [key, value] of Object.entries(sourceHeaders)) headers[String(key).toLowerCase()] = Array.isArray(value) ? String(value[0] ?? '') : String(value ?? '');
const rawBase64 = item.binary?.data?.data;
const raw = typeof rawBase64 === 'string' ? Buffer.from(rawBase64, 'base64') : Buffer.alloc(0);
const reject = (errorCode, statusCode) => [{ json: { authorized: false, status_code: statusCode, error: { error_code: errorCode } } }];
if (raw.length > 262144) return reject('PAYLOAD_TOO_LARGE', 413);
const eventKey = headers['x-oddroom-event-key'] ?? '';
const timestampText = headers['x-oddroom-timestamp'] ?? '';
const phase = headers['x-oddroom-resume-phase'] ?? '';
const supplied = headers['x-oddroom-signature'] ?? '';
if (!/^v1:[A-Za-z0-9-]{1,64}:[1-9][0-9]{0,19}:ORDER_CREATED$/.test(eventKey)) return reject('SIGNATURE_INVALID', 401);
if (!/^[1-9][0-9]{0,10}$/.test(timestampText) || !['created','deal_resolved','deal_upserted'].includes(phase)) return reject('SIGNATURE_INVALID', 401);
if (!/^v1=[0-9a-f]{64}$/.test(supplied)) return reject('SIGNATURE_INVALID', 401);
const secret = String($env.ODDROOM_WEBHOOK_HMAC_KEY ?? '');
if (secret.length < 16) throw new Error('HMAC credential alias is unavailable');
const base = Buffer.concat([Buffer.from(`${timestampText}.${eventKey}.${phase}.`, 'utf8'), raw]);
const expected = 'v1=' + crypto.createHmac('sha256', secret).update(base).digest('hex');
const providedBytes = Buffer.from(supplied, 'utf8');
const expectedBytes = Buffer.from(expected, 'utf8');
if (providedBytes.length !== expectedBytes.length || !crypto.timingSafeEqual(providedBytes, expectedBytes)) return reject('SIGNATURE_INVALID', 401);
const timestamp = Number(timestampText);
if (!Number.isSafeInteger(timestamp) || Math.abs(Math.floor(Date.now() / 1000) - timestamp) > 300) return reject('TIMESTAMP_EXPIRED', 401);
let payload;
try { payload = JSON.parse(raw.toString('utf8')); } catch { return reject('PAYLOAD_INVALID', 400); }
const order = payload?.order;
const valid = payload?.schema_version === '1' && payload?.event_key === eventKey && typeof payload?.shop_instance_id === 'string' && payload.shop_instance_id.length >= 1 && payload.shop_instance_id.length <= 64 && typeof payload?.run_id === 'string' && /^[0-9a-f-]{36}$/.test(payload.run_id) && payload?.event_type === 'ORDER_CREATED' && payload?.state_rank === 10 && typeof payload?.occurred_at_utc === 'string' && payload?.occurred_at_source === 'date_created' && order && Number.isInteger(order.id) && order.id > 0 && typeof order.number === 'string' && order.number.length >= 1 && order.number.length <= 255 && /^[A-Z]{3}$/.test(order.currency ?? '') && /^(?:0|[1-9][0-9]{0,17})\.[0-9]{2}$/.test(order.total ?? '') && order.customer && typeof order.customer.email === 'string' && /^[^@\s]+@example\.com$/.test(order.customer.email) && Array.isArray(order.items) && order.items.length >= 1 && order.items.length <= 100 && Array.isArray(order.coupon_codes) && order.coupon_codes.length <= 50;
if (!valid) return reject(payload?.schema_version === '1' ? 'PAYLOAD_INVALID' : 'SCHEMA_UNSUPPORTED', 400);
const expectedKey = `v1:${payload.shop_instance_id}:${order.id}:ORDER_CREATED`;
if (eventKey !== expectedKey) return reject('PAYLOAD_INVALID', 400);
const orderKey = `${payload.shop_instance_id}:${order.id}`;
return [{ json: { authorized: true, event_key: eventKey, resume_phase: phase, payload, order_key: orderKey, read_body: { idProperty: 'oddroom_wc_order_key', properties: ['oddroom_wc_order_key','oddroom_order_state','oddroom_order_state_rank','oddroom_last_event_at','oddroom_last_event_key','dealname','pipeline','dealstage'], inputs: [{ id: orderKey }] } } }];

const context = $('Verify HMAC Then Decode').first().json;
const response = $input.first().json;
const statusCode = Number(response.statusCode ?? 200);
const body = response.body ?? response;
const envelope = (result, phase, dealId, retryable, errorCode, errorMessage) => ({ schema_version: '1', event_key: context.event_key, result, processing_phase: phase, remote_contact_id: null, remote_deal_id: dealId ?? null, slack_status: 'not_required', slack_message_ts: null, retryable, retry_after_seconds: null, error_code: errorCode ?? null, error_message: errorMessage ?? null });
if (statusCode < 200 || statusCode >= 300) return [{ json: { should_upsert: false, response_code: 503, envelope: envelope('retryable_error', context.resume_phase, null, true, 'HUBSPOT_RETRYABLE', 'HubSpot Deal resolution was unavailable.') } }];
const results = Array.isArray(body?.results) ? body.results : [];
if (body?.status && body.status !== 'COMPLETE') return [{ json: { should_upsert: false, response_code: 503, envelope: envelope('retryable_error', context.resume_phase, null, true, 'HUBSPOT_RETRYABLE', 'HubSpot Deal resolution did not complete.') } }];
if (results.length > 1) return [{ json: { should_upsert: false, response_code: 422, envelope: envelope('terminal_error', context.resume_phase, null, false, 'HUBSPOT_SCHEMA', 'Deal identity resolution was ambiguous.') } }];
const existing = results[0] ?? null;
const existingRank = existing ? Number(existing.properties?.oddroom_order_state_rank ?? -1) : -1;
const existingKey = existing?.properties?.oddroom_last_event_key ?? null;
if (existing && existingRank > context.payload.state_rank) return [{ json: { should_upsert: false, response_code: 200, envelope: envelope('stale_ignored', 'completed', String(existing.id), false, null, null) } }];
if (existing && existingRank === context.payload.state_rank && existingKey && existingKey !== context.event_key) return [{ json: { should_upsert: false, response_code: 422, envelope: envelope('terminal_error', 'deal_resolved', String(existing.id), false, 'RESUME_PHASE_CONFLICT', 'Equal-rank remote state has a different event key.') } }];
const order = context.payload.order;
const upsertBody = { inputs: [{ id: context.order_key, idProperty: 'oddroom_wc_order_key', properties: { dealname: `OddRoom order ${order.number}`, pipeline: String($env.HUBSPOT_PIPELINE_ID), dealstage: String($env.HUBSPOT_INITIAL_STAGE_ID), oddroom_wc_order_key: context.order_key, oddroom_order_state: context.payload.event_type, oddroom_order_state_rank: String(context.payload.state_rank), oddroom_last_event_at: context.payload.occurred_at_utc, oddroom_last_event_key: context.event_key } }] };
return [{ json: { should_upsert: true, response_code: null, envelope: null, existing_deal_id: existing ? String(existing.id) : null, upsert_body: upsertBody, trace: ['created','deal_resolved'] } }];

const context = $('Verify HMAC Then Decode').first().json;
const prepared = $('Resolve Monotonic Deal State').first().json;
const response = $input.first().json;
const statusCode = Number(response.statusCode ?? 200);
const body = response.body ?? response;
const results = Array.isArray(body?.results) ? body.results : [];
const complete = statusCode >= 200 && statusCode < 300 && (!body?.status || body.status === 'COMPLETE') && results.length === 1 && String(results[0]?.id ?? '') !== '';
if (!complete) return [{ json: { response_code: 503, envelope: { schema_version: '1', event_key: context.event_key, result: 'retryable_error', processing_phase: 'deal_resolved', remote_contact_id: null, remote_deal_id: prepared.existing_deal_id ?? null, slack_status: 'not_required', slack_message_ts: null, retryable: true, retry_after_seconds: null, error_code: 'HUBSPOT_RETRYABLE', error_message: 'HubSpot Deal upsert did not complete.' }, trace: ['created','deal_resolved'] } }];
return [{ json: { response_code: 200, envelope: { schema_version: '1', event_key: context.event_key, result: 'completed', processing_phase: 'completed', remote_contact_id: null, remote_deal_id: String(results[0].id), slack_status: 'not_required', slack_message_ts: null, retryable: false, retry_after_seconds: null, error_code: null, error_message: null }, trace: ['created','deal_resolved','deal_upserted','completed'] } }];
